                # Update video metadata (in a real system, update the database)
                video_metadata[filename] = {'duration': get_video_duration(filename), 'resolutions': resolutions}
            else:
                logging.error(f"Transcoding failed for {filename}.")
        except queue.Empty:
            pass  # No transcoding jobs in the queue
        except Exception as e:
            logging.error(f"Error in transcoding worker: {e}")
        finally:
            transcoding_queue.task_done()

